import { IsString, IsNotEmpty, IsNumber, Min, IsOptional, Validate, registerDecorator, ValidationOptions } from 'class-validator';

// Validateur personnalisé pour multiple de 50
function IsMultipleOf(divisor: number, validationOptions?: ValidationOptions) {
  return function (object: object, propertyName: string) {
    registerDecorator({
      name: 'isMultipleOf',
      target: object.constructor,
      propertyName: propertyName,
      options: validationOptions,
      validator: {
        validate(value: number) {
          return value % divisor === 0;
        },
        defaultMessage() {
          return `Le prix doit être un multiple de ${divisor} FCFA`;
        }
      }
    });
  };
}

export class CreateProductDto {
  @IsString()
  @IsNotEmpty()
  name: string;

  @IsNumber()
  @Min(0)
  @IsMultipleOf(50)
  price: number;

  @IsString()
  @IsOptional()
  description?: string;

  @IsNumber()
  @Min(0)
  stock: number;

  @IsString()
  @IsNotEmpty()
  sku: string; // L'unicité sera gérée par la base de données
}
