Stratégie recommandée : 
1. Utiliser le package `sharp` pour le traitement d'images côté serveur (plus performant que d'autres librairies).
2. Créer un service `ImageProcessingService` avec une méthode `resizeAndUpload` qui :
   - Pour chaque fichier reçu, crée 3 buffers/image avec les dimensions cibles.
   - Upload chaque version vers Cloudinary avec des transformations natives (optionellement, Cloudinary peut redimensionner à la volée via des paramètres d'URL).
3. Stocker en base de données un objet JSON contenant les URLs des 3 versions.

Exemple d'implémentation avec sharp :
```typescript
import sharp from 'sharp';

async processImage(file: Express.Multer.File) {
  const sizes = [
    { name: 'thumbnail', width: 150, height: 150 },
    { name: 'medium', width: 500, height: 500 },
    { name: 'large', width: 1200, height: 1200 },
  ];

  const results = {};
  for (const size of sizes) {
    const resizedBuffer = await sharp(file.buffer)
      .resize(size.width, size.height, { fit: 'cover' })
      .toBuffer();
    const uploadResult = await cloudinary.uploader.upload(`data:image/jpeg;base64,${resizedBuffer.toString('base64')}`);
    results[size.name] = uploadResult.secure_url;
  }
  return results;
}
```

```typescript
import { Controller, Get, Post, Body, Patch, Param, Delete, UseGuards, ParseIntPipe, NotFoundException } from '@nestjs/common';
import { ProductsService } from './products.service';
import { CreateProductDto } from './dto/create-product.dto';
import { UpdateProductDto } from './dto/update-product.dto';
import { JwtAuthGuard } from '../auth/guards/jwt-auth.guard';
import { RolesGuard } from '../auth/guards/roles.guard';
import { Roles } from '../auth/decorators/roles.decorator';
import { ApiTags, ApiOperation, ApiResponse } from '@nestjs/swagger';

@ApiTags('products')
@Controller('products')
export class ProductsController {
  constructor(private readonly productsService: ProductsService) {}

  @Post()
  @Roles('admin', 'seller')
  @UseGuards(JwtAuthGuard, RolesGuard)
  @ApiOperation({ summary: 'Créer un nouveau produit' })
  @ApiResponse({ status: 201, description: 'Produit créé avec succès' })
  @ApiResponse({ status: 403, description: 'Accès interdit' })
  create(@Body() createProductDto: CreateProductDto) {
    return this.productsService.create(createProductDto);
  }

  @Get(':id')
  @ApiOperation({ summary: 'Récupérer un produit par son ID' })
  @ApiResponse({ status: 200, description: 'Produit trouvé' })
  @ApiResponse({ status: 404, description: 'Produit non trouvé' })
  async findOne(@Param('id', ParseIntPipe) id: number) {
    const product = await this.productsService.findOne(id);
    if (!product) {
      throw new NotFoundException(`Produit avec l'ID ${id} non trouvé`);
    }
    return product;
  }

  @Patch(':id')
  @Roles('admin', 'seller')
  @UseGuards(JwtAuthGuard, RolesGuard)
  @ApiOperation({ summary: 'Mettre à jour un produit' })
  async update(
    @Param('id', ParseIntPipe) id: number,
    @Body() updateProductDto: UpdateProductDto
  ) {
    const product = await this.productsService.update(id, updateProductDto);
    if (!product) {
      throw new NotFoundException(`Produit avec l'ID ${id} non trouvé`);
    }
    return product;
  }

  @Delete(':id')
  @Roles('admin')
  @UseGuards(JwtAuthGuard, RolesGuard)
  @ApiOperation({ summary: 'Supprimer un produit (soft delete)' })
  async remove(@Param('id', ParseIntPipe) id: number) {
    const result = await this.productsService.remove(id);
    if (!result) {
      throw new NotFoundException(`Produit avec l'ID ${id} non trouvé`);
    }
    return { message: 'Produit supprimé avec succès' };
  }
}
